import{_ as a,c as e,o as r,a4 as t}from"./chunks/framework.nQaBHiNx.js";const p=JSON.parse('{"title":"第二章 程序设计语言基础","description":"","frontmatter":{"permalink":"/basic/ruankao/software-designer/02-programming-language.html"},"headers":[],"relativePath":"computer/ruankao/software-designer/02-第二章 程序设计语言基础.md","filePath":"computer/ruankao/software-designer/02-第二章 程序设计语言基础.md"}'),o={name:"computer/ruankao/software-designer/02-第二章 程序设计语言基础.md"},i=t('<h1 id="第二章-程序设计语言基础" tabindex="-1">第二章 程序设计语言基础 <a class="header-anchor" href="#第二章-程序设计语言基础" aria-label="Permalink to &quot;第二章 程序设计语言基础&quot;">​</a></h1><p>程序设计语言是为了书写计算机程序而人为设计的符号语言，用于对计算过程进行描述、组织和推导。程序设计语言的广泛使用始于 1957 年出现的 FORTRAN ，程序设计语言的发展是一个不断演化的过程，其根本的推动力是更高的抽象机制以及对程序设计思想的更好支持。</p><h2 id="_2-1-程序设计语言概述" tabindex="-1">2.1 程序设计语言概述 <a class="header-anchor" href="#_2-1-程序设计语言概述" aria-label="Permalink to &quot;2.1 程序设计语言概述&quot;">​</a></h2><h3 id="_2-1-1-程序设计语言的基本概念" tabindex="-1">2.1.1 程序设计语言的基本概念 <a class="header-anchor" href="#_2-1-1-程序设计语言的基本概念" aria-label="Permalink to &quot;2.1.1 程序设计语言的基本概念&quot;">​</a></h3><ol><li>低级语言和高级语言</li><li>编译型程序和解释型程序</li><li>程序设计语言的定义</li><li>程序设计语言的分类</li></ol><h3 id="_2-1-2-程序设计语言的基本成分" tabindex="-1">2.1.2 程序设计语言的基本成分 <a class="header-anchor" href="#_2-1-2-程序设计语言的基本成分" aria-label="Permalink to &quot;2.1.2 程序设计语言的基本成分&quot;">​</a></h3><p>程序设计语言的基本成分包括数据、运算、控制和传输等。</p><h2 id="_2-2-语言处理程序基础" tabindex="-1">2.2 语言处理程序基础 <a class="header-anchor" href="#_2-2-语言处理程序基础" aria-label="Permalink to &quot;2.2 语言处理程序基础&quot;">​</a></h2><p>语言处理程序是一类系统软件的总称，其主要作用是将高级语言或汇编语言编写的程序翻译成某种机器语言程序，使程序可在计算机上运行。语言处理程序主要分为汇编程序、汇编程序和解释程序 3 种基本类型。</p><h3 id="_2-2-1-汇编程序基本原理" tabindex="-1">2.2.1 汇编程序基本原理 <a class="header-anchor" href="#_2-2-1-汇编程序基本原理" aria-label="Permalink to &quot;2.2.1 汇编程序基本原理&quot;">​</a></h3><h3 id="_2-2-2-编译程序基本原理" tabindex="-1">2.2.2 编译程序基本原理 <a class="header-anchor" href="#_2-2-2-编译程序基本原理" aria-label="Permalink to &quot;2.2.2 编译程序基本原理&quot;">​</a></h3><h3 id="_2-2-3-解释程序基本原理" tabindex="-1">2.2.3 解释程序基本原理 <a class="header-anchor" href="#_2-2-3-解释程序基本原理" aria-label="Permalink to &quot;2.2.3 解释程序基本原理&quot;">​</a></h3>',12),_=[i];function l(n,h,s,d,c,u){return r(),e("div",null,_)}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
